    expect(result).toContainEqual([1, 1]);
  });
  it.todo("should keep a block pattern stable when all cells have exactly three neighbors (survival)");
  it.todo("should oscillate a blinker pattern (combines underpopulation, survival, and reproduction)");
  it.todo("should kill a cell with more than three neighbors (overpopulation)");
});

